function g(t){if(!t)return"-";const e=new Date(t);if(isNaN(e.getTime()))return t;const r=e.getFullYear(),n=String(e.getMonth()+1).padStart(2,"0"),o=String(e.getDate()).padStart(2,"0");return`${r}-${n}-${o}`}function f(t){if(!t)return"-";const e=new Date(t);if(isNaN(e.getTime()))return t;const r=e.getFullYear(),n=String(e.getMonth()+1).padStart(2,"0"),o=String(e.getDate()).padStart(2,"0"),a=String(e.getHours()).padStart(2,"0"),c=String(e.getMinutes()).padStart(2,"0");return`${r}-${n}-${o} ${a}:${c}`}function l(t){return t==null?"¥0.00":`¥${Number(t).toFixed(2)}`}const s={0:{text:"排队中",color:"primary"},1:{text:"待支付",color:"warning"},2:{text:"已支付",color:"success"},3:{text:"已就诊",color:"default"},4:{text:"已退号",color:"danger"}};function S(t){return s[t]||{text:"未知",color:"default"}}const i={0:{text:"待审核",color:"warning"},1:{text:"审核通过",color:"success"},2:{text:"已驳回",color:"danger"}};function d(t){return i[t]||{text:"未知",color:"default"}}const u={1:"上午",2:"下午",3:"晚上"};function x(t){return u[t]||"未知班次"}export{g as a,l as b,S as c,d,f,x as g};
